use std::collections::{VecDeque, HashMap};

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut graph = vec![vec![]; n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        graph[u].push((v, w));
    }

    let mut dist = vec![i64::MAX; n];
    dist[0] = 0;
    let mut queue = VecDeque::new();
    queue.push_back(0);
    let mut visited = vec![false; n];
    let mut switch_used = vec![false; n];

    while let Some(u) = queue.pop_front() {
        if visited[u] {
            continue;
        }
        visited[u] = true;

        // Regular edge
        for (v, w) in &graph[u] {
            if dist[*v] > dist[u] + w {
                dist[*v] = dist[u] + w;
                queue.push_back(*v);
            }
        }

        // Switch edge (if not used)
        if !switch_used[u] {
            for (v, w) in &graph[u] {
                if dist[*v] > dist[u] + 2 * w {
                    dist[*v] = dist[u] + 2 * w;
                    queue.push_back(*v);
                }
            }
            switch_used[u] = true;
        }
    }

    if dist[n - 1] == i64::MAX {
        return -1;
    }
    dist[n - 1]
}
