        for &(v, w) in &graph[u] {
            if dist[v] > d + w {
                dist[v] = d + w;
                queue.push_back((v, dist[v]));
            }
        }

        // Check if we can flip the edge coming into u
        for &(v, w) in &graph[u] {
            if v == u {
                continue; // Skip self-loop
            }
            let reversed_w = 2 * w;
            if dist[v] > d + reversed_w {
                dist[v] = d + reversed_w;
                queue.push_back((v, dist[v]));
            }
        }
    }

    if dist[n - 1] == i64::MAX {
        return -1;
    }
    dist[n - 1]
